macro.museum_dbt.create_ticket_demand_fo.macro_sql:
{% macro create_ticket_demand_forecast() %}
    {#
        Creates a Snowflake ML FORECAST model for ticket demand prediction.
        Forecasts daily ticket reservations per ticket type for the next 90 days.

        Usage:
            dbt run-operation create_ticket_demand_forecast

        Prerequisites:
            - ml_ticket_demand_features must be populated
            - Requires warehouse with ML capabilities

        The forecast uses multi-series mode (one series per ticket_type).
    #}

    {% if execute %}

        {% set create_model %}
            CREATE OR REPLACE SNOWFLAKE.ML.FORECAST MUSEUM_DW_DEV.ML_FEATURES.FORECAST_TICKET_DEMAND(
                INPUT_DATA => SYSTEM$QUERY_REFERENCE(
                    'SELECT
                        entry_date::TIMESTAMP_NTZ AS ds,
                        ticket_type AS series,
                        daily_reserved AS y
                    FROM MUSEUM_DW_DEV.ML_FEATURES.ML_TICKET_DEMAND_FEATURES
                    WHERE entry_date IS NOT NULL
                    ORDER BY ticket_type, entry_date'
                ),
                SERIES_COLNAME => 'SERIES',
                TIMESTAMP_COLNAME => 'DS',
                TARGET_COLNAME => 'Y'
            )
        {% endset %}

        {% do run_query(create_model) %}
        {{ log("FORECAST: Model FORECAST_TICKET_DEMAND created successfully.", info=True) }}
        {{ log("FORECAST: Run forecasts with:", info=True) }}
        {{ log("  CALL MUSEUM_DW_DEV.ML_FEATURES.FORECAST_TICKET_DEMAND!FORECAST(FORECASTING_PERIODS => 90);", info=True) }}

    {% endif %}

{% endmacro %}

macro.museum_dbt.test_z_score_outlier.macro_sql:
{% test z_score_outlier(model, column_name, max_zscore=3) %}
WITH stats AS (
    SELECT
        AVG({{ column_name }}) AS mean_val,
        STDDEV({{ column_name }}) AS stddev_val
    FROM {{ model }}
    WHERE {{ column_name }} IS NOT NULL
)
SELECT {{ column_name }}
FROM {{ model }}, stats
WHERE stats.stddev_val > 0
  AND ABS(({{ column_name }} - stats.mean_val) / stats.stddev_val) > {{ max_zscore }}
{% endtest %}

macro.museum_dbt.test_positive_value.macro_sql:
{% test positive_value(model, column_name) %}
SELECT {{ column_name }}
FROM {{ model }}
WHERE {{ column_name }} < 0
{% endtest %}

macro.museum_dbt.test_value_between.macro_sql:
{% test value_between(model, column_name, min_value, max_value) %}
SELECT {{ column_name }}
FROM {{ model }}
WHERE {{ column_name }} < {{ min_value }}
   OR {{ column_name }} > {{ max_value }}
{% endtest %}

macro.museum_dbt.test_null_rate_threshol.macro_sql:
{% test null_rate_threshold(model, column_name, max_null_pct=50) %}
WITH rates AS (
    SELECT
        COUNT(*) AS total_rows,
        COUNT(CASE WHEN {{ column_name }} IS NULL THEN 1 END) AS null_rows
    FROM {{ model }}
)
SELECT total_rows, null_rows,
       ROUND(null_rows::FLOAT / NULLIF(total_rows, 0) * 100, 2) AS null_pct
FROM rates
WHERE ROUND(null_rows::FLOAT / NULLIF(total_rows, 0) * 100, 2) > {{ max_null_pct }}
{% endtest %}

macro.museum_dbt.test_late_arriving_data.macro_sql:
{% test late_arriving_data(model, timestamp_column, max_lag_hours=72) %}
SELECT {{ timestamp_column }}
FROM {{ model }}
WHERE {{ timestamp_column }} < DATEADD('hour', -{{ max_lag_hours }}, CURRENT_TIMESTAMP())
  AND _loaded_at > DATEADD('hour', -24, CURRENT_TIMESTAMP())
{% endtest %}

macro.museum_dbt.test_daily_volume_bound.macro_sql:
{% test daily_volume_bounds(model, date_column, min_rows_per_day=1, max_rows_per_day=10000) %}
WITH daily_counts AS (
    SELECT
        {{ date_column }} AS day_val,
        COUNT(*) AS row_count
    FROM {{ model }}
    GROUP BY 1
)
SELECT day_val, row_count
FROM daily_counts
WHERE row_count < {{ min_rows_per_day }}
   OR row_count > {{ max_rows_per_day }}
{% endtest %}

macro.museum_dbt.test_cardinality_change.macro_sql:
{% test cardinality_change(model, column_name, min_expected=1, max_expected=100) %}
WITH card AS (
    SELECT COUNT(DISTINCT {{ column_name }}) AS distinct_count
    FROM {{ model }}
)
SELECT distinct_count
FROM card
WHERE distinct_count < {{ min_expected }}
   OR distinct_count > {{ max_expected }}
{% endtest %}

macro.museum_dbt.test_distribution_shift.macro_sql:
{% test distribution_shift(model, column_name, value, min_pct=0, max_pct=100) %}
WITH counts AS (
    SELECT
        COUNT(*) AS total_rows,
        COUNT(CASE WHEN {{ column_name }} = '{{ value }}' THEN 1 END) AS value_rows
    FROM {{ model }}
)
SELECT total_rows, value_rows,
       ROUND(value_rows::FLOAT / NULLIF(total_rows, 0) * 100, 2) AS actual_pct
FROM counts
WHERE ROUND(value_rows::FLOAT / NULLIF(total_rows, 0) * 100, 2) < {{ min_pct }}
   OR ROUND(value_rows::FLOAT / NULLIF(total_rows, 0) * 100, 2) > {{ max_pct }}
{% endtest %}

macro.museum_dbt.generate_hashdiff.macro_sql:
{% macro generate_hashdiff(columns) %}
    MD5(CONCAT_WS('||',
        {% for column in columns %}
        COALESCE(CAST({{ column }} AS VARCHAR), '^^NULL^^'){{ ',' if not loop.last }}
        {% endfor %}
    ))
{% endmacro %}

macro.museum_dbt.test_hashdiff_integrity.macro_sql:
{% test hashdiff_integrity(model, hashdiff_column='hashdiff', unique_key='id') %}

WITH collision_check AS (
    SELECT
        {{ hashdiff_column }} AS check_value,
        'COLLISION' AS issue_type
    FROM {{ model }}
    WHERE {{ hashdiff_column }} IS NOT NULL
    GROUP BY {{ hashdiff_column }}
    HAVING COUNT(DISTINCT {{ unique_key }}) > 1
),
null_check AS (
    SELECT
        {{ unique_key }}::VARCHAR AS check_value,
        'NULL_HASH' AS issue_type
    FROM {{ model }}
    WHERE {{ hashdiff_column }} IS NULL
)
SELECT * FROM collision_check
UNION ALL
SELECT * FROM null_check

{% endtest %}

macro.dbt_snowflake.get_column_comment_s.macro_sql:
{% macro get_column_comment_sql(column_name, column_dict) -%}
  {% if (column_name|upper in column_dict) -%}
    {% set matched_column = column_name|upper -%}
  {% elif (column_name|lower in column_dict) -%}
    {% set matched_column = column_name|lower -%}
  {% elif (column_name in column_dict) -%}
    {% set matched_column = column_name -%}
  {% else -%}
    {% set matched_column = None -%}
  {% endif -%}
  {% if matched_column -%}
    {{ adapter.quote(column_name) }} COMMENT $${{ column_dict[matched_column]['description'] | replace('$', '[$]') }}$$
  {%- else -%}
    {{ adapter.quote(column_name) }} COMMENT $$$$
  {%- endif -%}
{% endmacro %}

